# New algorithm description: {The 'Proximity-Cluster Prioritization' algorithm combines the distance from the current truck position with a clustering index that represents customer density, using a balance between these two factors to determine the next customer node to visit for efficient routing.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    # Calculate clustering index as proximity of a customer to other unvisited customers
    clustering_indices = np.zeros(len(unvisited_customers))
    for i in range(len(unvisited_customers)):
        cluster_sum = 0
        for j in range(len(unvisited_customers)):
            if i != j:
                cluster_sum += np.linalg.norm(unvisited_customers[i] - unvisited_customers[j])
        clustering_indices[i] = cluster_sum

    min_score = float('inf')
    best_node = None

    for idx, customer in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(cur_truck_pos - customer)
        # Consider the clustering index, where lower values indicate a denser cluster
        cluster_weight = 1 / (1 + clustering_indices[idx])
        score = distance_to_customer * cluster_weight

        if score < min_score:
            min_score = score
            best_node = idx

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    def euclidean_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    cur_truck_pos = np.array(cur_truck_pos)
    depot_pos = np.array(depot_pos)
    truck_positions = [np.array(pos) for pos in all_truck_pos]
    unvisited_positions = [np.array(pos) for pos in unvisited_customers]

    best_node = None
    min_score = float('inf')

    for i, customer_pos in enumerate(unvisited_positions):
        distance = euclidean_distance(cur_truck_pos, customer_pos)
        congestion_penalty = sum(1 / (1 + euclidean_distance(truck_pos, customer_pos))
                                 for truck_pos in truck_positions)

        return_to_depot_cost = (euclidean_distance(customer_pos, depot_pos) ** 2) / max(len(unvisited_customers)-1, 1)

        score = distance + congestion_penalty + return_to_depot_cost

        if score < min_score:
            min_score = score
            best_node = i

    return best_node
